def ttl_cached_property(ttl_seconds):
    class TTLCachedProperty:
        def __init__(self, func):
            self.func = func
            self.ttl = ttl_seconds
            self.attr = '_' + func.__name__
            self.ts_attr = '_' + func.__name__ + '_ts'

        def __get__(self, obj, objtype=None):
            if obj is None: return self
            now = time.monotonic()
            ts = getattr(obj, self.ts_attr, 0)
            if (now - ts) < self.ttl:
                return getattr(obj, self.attr)
            value = self.func(obj)
            setattr(obj, self.attr, value)
            setattr(obj, self.ts_attr, now)
            return value
    return TTLCachedProperty

